package main

import "fmt"

type person struct {
	name string
	age  int
}

func greet(p person) {
	fmt.Printf("Hello, %s! You are %d years old.\n", p.name, p.age)
}

func main() {
	p := person{name: "Alex", age: 25}
	greet(p)
}

