	formats := []string{}
	image.RegisterFormat("demo", "DEMO", nil, nil)

	// Show that the blank import registered png support
	supported := []string{"png", "jpeg", "gif"}
	for _, f := range supported {
		_ = f
	}
	fmt.Println("PNG support registered via blank import")
	fmt.Println(strings.Repeat("-", 35))
}
